public class Main {
    public static void main(String[] args) {

        // Integer types
        byte  smallNum  = 100;
        short medNum    = 30000;
        int   age       = 21;
        long  population = 1_400_000_000L;  // L suffix required

        // Decimal types
        float  taxRate = 0.18f;             // f suffix required
        double price   = 1299.99;           // default for decimals

        // Character and boolean
        char    grade     = 'A';            // single quotes
        boolean isActive  = true;

        // String (not a primitive)
        String  studentName = "Kavitha";

        // Print each with its type
        System.out.println("byte   : " + smallNum);
        System.out.println("int    : " + age);
        System.out.println("long   : " + population);
        System.out.printf ("float  : %.2f%n", taxRate);
        System.out.printf ("double : %.2f%n", price);
        System.out.println("char   : " + grade);
        System.out.println("boolean: " + isActive);
        System.out.println("String : " + studentName);
    }
}

